export interface CSVOptions {
  delimiter?: string;
  quote?: string;
  lineSeparator?: string;
}

export interface CSVError {
  row: number;
  message: string;
}

export interface CSVResult {
  rows: Record<string, any>[];
  headers: string[];
  errors: CSVError[];
  filter(predicate: (row: Record<string, any>) => boolean): Record<string, any>[];
  sum(column: string): number;
  average(column: string): number;
  count(): number;
  groupBy(column: string): Map<any, Record<string, any>[]>;
}

const normalizeInput = (input: string, lineSeparator: string): string => {
  if (lineSeparator === "\n") {
    return input.replace(/\r\n/g, "\n").replace(/\r/g, "\n");
  }
  return input;
};

const coerceValue = (value: string): any => {
  const trimmed = value.trim();
  if (trimmed === "") {
    return null;
  }
  const lower = trimmed.toLowerCase();
  if (lower === "null") {
    return null;
  }
  if (lower === "true") {
    return true;
  }
  if (lower === "false") {
    return false;
  }
  if (/^-?\d+(\.\d+)?$/.test(trimmed)) {
    const numberValue = Number(trimmed);
    return Number.isNaN(numberValue) ? value : numberValue;
  }
  return value;
};

const parseRows = (
  input: string,
  options: Required<CSVOptions>,
): { rows: string[][]; errors: CSVError[] } => {
  const { delimiter, quote, lineSeparator } = options;
  const normalizedInput = normalizeInput(input, lineSeparator);
  const rows: string[][] = [];
  const errors: CSVError[] = [];
  let currentRow: string[] = [];
  let currentField = "";
  let inQuotes = false;
  let lineNumber = 1;

  const pushField = () => {
    currentRow.push(currentField);
    currentField = "";
  };

  const pushRow = () => {
    rows.push(currentRow);
    currentRow = [];
  };

  for (let i = 0; i < normalizedInput.length; i += 1) {
    const char = normalizedInput[i];

    if (inQuotes) {
      if (char === quote) {
        const nextChar = normalizedInput[i + 1];
        if (nextChar === quote) {
          currentField += quote;
          i += 1;
        } else {
          inQuotes = false;
        }
      } else {
        currentField += char;
      }
      continue;
    }

    if (
      lineSeparator.length > 0 &&
      normalizedInput.startsWith(lineSeparator, i)
    ) {
      pushField();
      pushRow();
      lineNumber += 1;
      i += lineSeparator.length - 1;
      continue;
    }

    if (char === delimiter) {
      pushField();
      continue;
    }

    if (char === quote && currentField.length === 0) {
      inQuotes = true;
      continue;
    }

    currentField += char;
  }

  if (inQuotes) {
    errors.push({
      row: lineNumber,
      message: "Unclosed quoted field",
    });
  }

  if (currentField.length > 0 || currentRow.length > 0) {
    pushField();
    pushRow();
  }

  return { rows, errors };
};

export const parseCSV = (input: string, options: CSVOptions = {}): CSVResult => {
  const settings: Required<CSVOptions> = {
    delimiter: options.delimiter ?? ",",
    quote: options.quote ?? '"',
    lineSeparator: options.lineSeparator ?? "\n",
  };

  if (input.trim() === "") {
    return {
      rows: [],
      headers: [],
      errors: [],
      filter: () => [],
      sum: () => 0,
      average: () => 0,
      count: () => 0,
      groupBy: () => new Map(),
    };
  }

  const parsed = parseRows(input, settings);
  const { rows: rawRows } = parsed;
  const errors: CSVError[] = [...parsed.errors];

  const headers = rawRows[0] ? rawRows[0] : [];
  const dataRows = rawRows.slice(1);

  const rows: Record<string, any>[] = dataRows.map((row, index) => {
    const rowNumber = index + 2;
    if (row.length !== headers.length) {
      errors.push({
        row: rowNumber,
        message: `Expected ${headers.length} columns but got ${row.length}`,
      });
    }
    const record: Record<string, any> = {};
    headers.forEach((header, columnIndex) => {
      const value = row[columnIndex] ?? "";
      record[header] = coerceValue(value);
    });
    return record;
  });

  const result: CSVResult = {
    rows,
    headers,
    errors,
    filter: (predicate) => rows.filter(predicate),
    sum: (column) =>
      rows.reduce((total, row) => {
        const value = row[column];
        return typeof value === "number" && !Number.isNaN(value)
          ? total + value
          : total;
      }, 0),
    average: (column) => {
      let total = 0;
      let count = 0;
      rows.forEach((row) => {
        const value = row[column];
        if (typeof value === "number" && !Number.isNaN(value)) {
          total += value;
          count += 1;
        }
      });
      return count === 0 ? 0 : total / count;
    },
    count: () => rows.length,
    groupBy: (column) => {
      const map = new Map<any, Record<string, any>[]>();
      rows.forEach((row) => {
        const key = row[column];
        const existing = map.get(key) ?? [];
        existing.push(row);
        map.set(key, existing);
      });
      return map;
    },
  };

  return result;
};

import { parseCSV } from "./csv-parser";

const assert = (condition: boolean, message: string) => {
  if (!condition) {
    throw new Error(message);
  }
};

const assertEqual = (actual: any, expected: any, message: string) => {
  const actualJson = JSON.stringify(actual);
  const expectedJson = JSON.stringify(expected);
  if (actualJson !== expectedJson) {
    throw new Error(`${message}. Expected ${expectedJson}, got ${actualJson}`);
  }
};

(() => {
  const input = "name,age\nAlice,30\nBob,25";
  const result = parseCSV(input);
  assertEqual(result.headers, ["name", "age"], "Headers should parse correctly");
  assertEqual(result.rows.length, 2, "Should parse two rows");
  assertEqual(result.rows[0], { name: "Alice", age: 30 }, "Row data parsed");
})();

(() => {
  const input = "name,desc\n\"Widget, large\",ok";
  const result = parseCSV(input);
  assertEqual(result.rows[0].desc, "Widget, large", "Quoted field with comma parsed");
})();

(() => {
  const input = "quote\n\"He said \"\"hi\"\"\"";
  const result = parseCSV(input);
  assertEqual(result.rows[0].quote, 'He said "hi"', "Escaped quotes parsed");
})();

(() => {
  const input = "name;age\n'Bob';'40'";
  const result = parseCSV(input, { delimiter: ";", quote: "'" });
  assertEqual(result.rows[0], { name: "Bob", age: 40 }, "Custom delimiter parsed");
})();

(() => {
  const input = "a,b,c,d,e,f,g\n1,2.5,true,FALSE,null,,text";
  const result = parseCSV(input);
  assertEqual(
    result.rows[0],
    { a: 1, b: 2.5, c: true, d: false, e: null, f: null, g: "text" },
    "Type coercion works",
  );
})();

(() => {
  const input = "a,b\n1\n2,3,4";
  const result = parseCSV(input);
  assertEqual(result.errors.length, 2, "Malformed rows generate errors");
  assert(result.errors[0].row === 2, "Error row should be line 2");
  assert(result.errors[1].row === 3, "Error row should be line 3");
  assertEqual(result.rows[0], { a: 1, b: null }, "Missing column filled with null");
})();

(() => {
  const input = "name,age\nAda,35\nBen,20\nCara,40";
  const result = parseCSV(input);
  const filtered = result.filter((row) => row.age > 30);
  assertEqual(filtered.length, 2, "Filter returns matching rows");
})();

(() => {
  const input = "category,value\nA,10\nA,5\nB,20";
  const result = parseCSV(input);
  assertEqual(result.sum("value"), 35, "Sum aggregates values");
  assertEqual(result.average("value"), 35 / 3, "Average aggregates values");
  assertEqual(result.count(), 3, "Count aggregates rows");
  const grouped = result.groupBy("category");
  assertEqual(grouped.get("A")?.length, 2, "GroupBy groups values");
  assertEqual(grouped.get("B")?.length, 1, "GroupBy groups values");
})();

(() => {
  const result = parseCSV("");
  assertEqual(result.headers, [], "Empty input yields no headers");
  assertEqual(result.rows, [], "Empty input yields no rows");
})();

(() => {
  const input = "single\n1\n2";
  const result = parseCSV(input);
  assertEqual(result.headers, ["single"], "Single column header parsed");
  assertEqual(result.rows.length, 2, "Single column rows parsed");
})();

(() => {
  const input = "a,b\n1,2";
  const result = parseCSV(input);
  assertEqual(result.rows.length, 1, "Single row parsed");
})();

(() => {
  const largeField = "x".repeat(10000);
  const input = `data\n\"${largeField}\"`;
  const result = parseCSV(input);
  assertEqual(result.rows[0].data.length, 10000, "Large field parsed");
})();

console.log("All CSV parser tests passed.");

